import{_ as a,c as t,o as s,a5 as n}from"./chunks/framework.CgT1UzWm.js";const m=JSON.parse(`{"title":"Resolved Parameters","titleTemplate":"NpgsqlRest","description":"Compute a routine parameter's value server-side from a SQL expression at request time, instead of taking it from the client — for injecting DB-stored API tokens, secrets, or derived values into outbound HTTP calls, headers, and parameters.","frontmatter":{"outline":[2,3],"title":"Resolved Parameters","titleTemplate":"NpgsqlRest","description":"Compute a routine parameter's value server-side from a SQL expression at request time, instead of taking it from the client — for injecting DB-stored API tokens, secrets, or derived values into outbound HTTP calls, headers, and parameters.","head":[["meta",{"name":"keywords","content":"npgsqlrest resolved parameter, server-side parameter, sql expression parameter, inject api token postgresql, secret in authorization header, resolved parameter expression"}],["meta",{"property":"og:title","content":"NpgsqlRest Resolved Parameters"}],["meta",{"property":"og:description","content":"Resolve a parameter's value server-side from SQL at request time, never from the client."}],["meta",{"property":"og:type","content":"article"}],["link",{"rel":"canonical","href":"https://npgsqlrest.github.io/annotations/resolved-parameters.html"}],["meta",{"property":"og:url","content":"https://npgsqlrest.github.io/annotations/resolved-parameters.html"}],["meta",{"property":"og:image","content":"https://npgsqlrest.github.io/og-image.png"}],["meta",{"name":"twitter:card","content":"summary_large_image"}],["meta",{"name":"twitter:title","content":"NpgsqlRest Resolved Parameters"}],["meta",{"name":"twitter:description","content":"Resolve a parameter's value server-side from SQL at request time, never from the client."}],["meta",{"name":"twitter:image","content":"https://npgsqlrest.github.io/og-image.png"}]]},"headers":[],"relativePath":"annotations/resolved-parameters.md","filePath":"annotations/resolved-parameters.md","lastUpdated":1780482668000}`),r={name:"annotations/resolved-parameters.md"};function i(o,e,l,p,c,d){return s(),t("div",null,e[0]||(e[0]=[n(`<h1 id="resolved-parameters" tabindex="-1">Resolved Parameters <a class="header-anchor" href="#resolved-parameters" aria-label="Permalink to &quot;Resolved Parameters&quot;">​</a></h1><p>A <strong>resolved parameter</strong> has its value computed <strong>server-side from a SQL expression</strong> at request time, instead of being supplied by the client. You declare it with a <code>param_name = &lt;sql&gt;</code> comment annotation where <code>param_name</code> matches a real routine parameter.</p><p>This is how you inject a value the caller must <strong>not</strong> provide or see — a DB-stored API token, a secret, or anything derived in SQL — into the routine and into <a href="./parameter-substitution.html"><code>{name}</code> placeholder substitution</a> (response headers, custom parameters, and <a href="./http-type.html">HTTP custom type</a> URL/headers/body).</p><details class="code-collapsible" open><summary>sql</summary><div class="language-sql vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">sql</span><pre class="shiki shiki-themes catppuccin-latte catppuccin-mocha vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#8839EF;--shiki-dark:#CBA6F7;">comment on function get_secure_data(_user_id int, _req my_api_type, _token text) is </span><span style="--shiki-light:#40A02B;--shiki-dark:#A6E3A1;">&#39;</span></span>
<span class="line"><span style="--shiki-light:#40A02B;--shiki-dark:#A6E3A1;">HTTP GET</span></span>
<span class="line"><span style="--shiki-light:#40A02B;--shiki-dark:#A6E3A1;">_token = select api_token from user_tokens where user_id = {_user_id}</span></span>
<span class="line"><span style="--shiki-light:#40A02B;--shiki-dark:#A6E3A1;">&#39;</span><span style="--shiki-light:#4C4F69;--shiki-dark:#CDD6F4;">;</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br></div></div></details><p>The client calls <code>GET /api/get-secure-data/?user_id=42</code>; the server runs <code>select api_token from user_tokens where user_id = 42</code>, binds the result to <code>_token</code>, and uses it wherever <code>{_token}</code> appears. The token never leaves the server, and a client <code>&amp;token=hacked</code> is ignored.</p><h2 id="syntax" tabindex="-1">Syntax <a class="header-anchor" href="#syntax" aria-label="Permalink to &quot;Syntax&quot;">​</a></h2><details class="code-collapsible" open><summary>code</summary><div class="language- vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes catppuccin-latte catppuccin-mocha vp-code" tabindex="0"><code><span class="line"><span>&lt;parameter_name&gt; = &lt;sql expression&gt;</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div></details><ul><li><code>parameter_name</code> must match an <strong>actual routine parameter</strong> (by its PostgreSQL name). If the key doesn&#39;t match a parameter, it&#39;s treated as a <a href="./custom-parameters.html">custom parameter</a> instead.</li><li><code>&lt;sql expression&gt;</code> is any scalar SQL expression — a column read, a subquery, a function call, concatenation, <code>coalesce</code>, etc. It is run with <code>ExecuteScalar</code>, so it must return a single value.</li><li>It may contain <code>{name}</code> placeholders referencing <strong>other</strong> parameters (resolved case-insensitively, by actual or converted name), which are passed as safe <code>$N</code> parameters — never string-concatenated.</li></ul><h2 id="behavior" tabindex="-1">Behavior <a class="header-anchor" href="#behavior" aria-label="Permalink to &quot;Behavior&quot;">​</a></h2><ul><li><strong>Server-side only.</strong> The resolved value cannot be overridden by client input. Even if the client sends <code>&amp;token=hacked</code>, the SQL-resolved value wins.</li><li><strong>Runs before the call.</strong> Resolved expressions execute <em>before</em> the outbound HTTP-type request and before placeholder substitution, so the resolved value is available everywhere the parameter is referenced.</li><li><strong>NULL handling.</strong> If the expression returns no rows or <code>NULL</code>, the parameter becomes SQL <code>NULL</code> (an empty string in placeholder substitution).</li><li><strong>SQL-injection safe.</strong> <code>{name}</code> placeholders inside the expression are converted to positional <code>$N</code> parameters.</li><li><strong>Sequential.</strong> Multiple resolved expressions run one-by-one on the same connection, in annotation order. A later expression can reference an earlier resolved parameter.</li><li><strong>Works with claims.</strong> Expressions can reference parameters auto-filled from JWT claims via <a href="./user-parameters.html">user parameters</a>, enabling fully zero-input authenticated calls.</li><li><strong>Hidden from callers.</strong> A resolved parameter is excluded from the client input surface and from MCP <code>tools/list</code> input schemas — an agent or caller can neither see nor set it.</li></ul><h2 id="examples" tabindex="-1">Examples <a class="header-anchor" href="#examples" aria-label="Permalink to &quot;Examples&quot;">​</a></h2><h3 id="inject-a-db-stored-api-token-into-an-outbound-call" tabindex="-1">Inject a DB-stored API token into an outbound call <a class="header-anchor" href="#inject-a-db-stored-api-token-into-an-outbound-call" aria-label="Permalink to &quot;Inject a DB-stored API token into an outbound call&quot;">​</a></h3><details class="code-collapsible" open><summary>sql</summary><div class="language-sql vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">sql</span><pre class="shiki shiki-themes catppuccin-latte catppuccin-mocha vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#8839EF;--shiki-dark:#CBA6F7;">comment on type weather_api is </span><span style="--shiki-light:#40A02B;--shiki-dark:#A6E3A1;">&#39;GET https://api.example.com/v1/current?city={_city}</span></span>
<span class="line"><span style="--shiki-light:#40A02B;--shiki-dark:#A6E3A1;">Authorization: Bearer {_api_key}&#39;</span><span style="--shiki-light:#4C4F69;--shiki-dark:#CDD6F4;">;</span></span>
<span class="line"></span>
<span class="line"><span style="--shiki-light:#8839EF;--shiki-dark:#CBA6F7;">comment on function get_weather(_city text, _api weather_api, _api_key text) is </span><span style="--shiki-light:#40A02B;--shiki-dark:#A6E3A1;">&#39;</span></span>
<span class="line"><span style="--shiki-light:#40A02B;--shiki-dark:#A6E3A1;">HTTP GET</span></span>
<span class="line"><span style="--shiki-light:#40A02B;--shiki-dark:#A6E3A1;">_api_key = select token from weather_tokens order by fetched_at desc limit 1</span></span>
<span class="line"><span style="--shiki-light:#40A02B;--shiki-dark:#A6E3A1;">&#39;</span><span style="--shiki-light:#4C4F69;--shiki-dark:#CDD6F4;">;</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br><span class="line-number">6</span><br><span class="line-number">7</span><br></div></div></details><p>The caller supplies only <code>_city</code>. <code>_api_key</code> is read from <code>weather_tokens</code> per request, so it always reflects the latest token — useful when a separate refresh/login routine periodically writes a new token into that table. (Pair it with <code>pg_cron</code> or a refresh routine to keep the row current; a tight-expiry variant: <code>… where expires_at &gt; now() order by fetched_at desc limit 1</code>.)</p><h3 id="multiple-resolved-parameters" tabindex="-1">Multiple resolved parameters <a class="header-anchor" href="#multiple-resolved-parameters" aria-label="Permalink to &quot;Multiple resolved parameters&quot;">​</a></h3><details class="code-collapsible" open><summary>sql</summary><div class="language-sql vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">sql</span><pre class="shiki shiki-themes catppuccin-latte catppuccin-mocha vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#8839EF;--shiki-dark:#CBA6F7;">comment on function my_func(_name text, _req my_type, _token text, _api_key text) is </span><span style="--shiki-light:#40A02B;--shiki-dark:#A6E3A1;">&#39;</span></span>
<span class="line"><span style="--shiki-light:#40A02B;--shiki-dark:#A6E3A1;">_token   = select api_token from tokens where user_name = {_name}</span></span>
<span class="line"><span style="--shiki-light:#40A02B;--shiki-dark:#A6E3A1;">_api_key = select &#39;&#39;static-key-&#39;&#39; || api_token from tokens where user_name = {_name}</span></span>
<span class="line"><span style="--shiki-light:#40A02B;--shiki-dark:#A6E3A1;">&#39;</span><span style="--shiki-light:#4C4F69;--shiki-dark:#CDD6F4;">;</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br></div></div></details><h3 id="resolved-value-in-url-header-and-body" tabindex="-1">Resolved value in URL, header, and body <a class="header-anchor" href="#resolved-value-in-url-header-and-body" aria-label="Permalink to &quot;Resolved value in URL, header, and body&quot;">​</a></h3><p>A resolved value participates in every placeholder location of an <a href="./http-type.html">HTTP custom type</a>:</p><details class="code-collapsible" open><summary>code</summary><div class="language- vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes catppuccin-latte catppuccin-mocha vp-code" tabindex="0"><code><span class="line"><span>-- URL:    GET https://api.example.com/resource/{_secret_path}</span></span>
<span class="line"><span>-- Header: Authorization: Bearer {_token}</span></span>
<span class="line"><span>-- Body:   {&quot;token&quot;: &quot;{_token}&quot;, &quot;data&quot;: &quot;{_payload}&quot;}</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br></div></div></details><h2 id="how-it-compares-to-the-other-name-sources" tabindex="-1">How it compares to the other <code>{name}</code> sources <a class="header-anchor" href="#how-it-compares-to-the-other-name-sources" aria-label="Permalink to &quot;How it compares to the other \`{name}\` sources&quot;">​</a></h2><p>A <code>{name}</code> placeholder can be filled three ways — pick by where the value comes from:</p><div class="table-container"><div class="table-wrapper"><table tabindex="0"><thead><tr><th>Source</th><th>Annotation</th><th>Use when</th></tr></thead><tbody><tr><td><strong>Request parameter</strong></td><td>(the parameter itself)</td><td>the caller provides the value</td></tr><tr><td><strong><a href="./parameter-substitution.html#environment-variables">Environment variable</a></strong></td><td><code>NpgsqlRest:AvailableEnvVars</code> allowlist</td><td>a static, per-deployment value (API key set at deploy, server name)</td></tr><tr><td><strong>Resolved parameter</strong> (this page)</td><td><code>param = &lt;sql&gt;</code></td><td>a value computed/looked-up server-side per request (DB-stored token, claim-derived secret) — must not come from the client</td></tr></tbody></table></div></div><h2 id="related" tabindex="-1">Related <a class="header-anchor" href="#related" aria-label="Permalink to &quot;Related&quot;">​</a></h2><ul><li><a href="./parameter-substitution.html">Parameter Value Substitution</a> - the <code>{name}</code> substitution mechanism and its sources</li><li><a href="./http-type.html">HTTP Custom Types</a> - outbound HTTP calls that consume resolved values</li><li><a href="./custom-parameters.html">Custom Parameters</a> - <code>@key = value</code> where the key is <em>not</em> a parameter</li><li><a href="./user-parameters.html">User Parameters</a> - auto-fill parameters from JWT claims</li><li><a href="./../config/http-client.html">HTTP Client Options</a> - configure the HTTP client</li></ul>`,24)]))}const u=a(r,[["render",i]]);export{m as __pageData,u as default};
